\section*{Análise dos Distratores}

\begin{itemize}

  \item \textbf{Alternativa A}
  \begin{itemize}
    \item \textit{Raciocínio provável}: O aluno pode pensar que a zona de amassamento aciona diretamente os airbags, por ambos serem dispositivos de segurança.
    \item \textit{Tipo de erro}: Causalidade incorreta.
    \item \textit{Razão pela plausibilidade}: Associar ambos os dispositivos à segurança veicular e colisões.
    \item \textit{Por que está errada}: Os airbags são acionados por sensores independentes que detectam desaceleração rápida, não pela deformação estrutural.
  \end{itemize}

  \item \textbf{Alternativa C}
  \begin{itemize}
    \item \textit{Raciocínio provável}: Confundir quantidade de movimento com energia, supondo que a deformação consome quantidade de movimento.
    \item \textit{Tipo de erro}: Confusão conceitual entre grandezas físicas.
    \item \textit{Razão pela plausibilidade}: A quantidade de movimento está relacionada ao impacto e à colisão.
    \item \textit{Por que está errada}: A quantidade de movimento do sistema isolado é conservada; a energia cinética é que é dissipada na deformação.
  \end{itemize}

  \item \textbf{Alternativa D}
  \begin{itemize}
    \item \textit{Raciocínio provável}: Pensar que a parte deformável age como uma barreira física que protege os ocupantes.
    \item \textit{Tipo de erro}: Interpretação literal do termo \emph{barreira}.
    \item \textit{Razão pela plausibilidade}: Barreira pode ser confundida com proteção rígida contra impacto.
    \item \textit{Por que está errada}: A zona de deformação não é uma barreira rígida, mas uma estrutura que se deforma para absorver energia.
  \end{itemize}

  \item \textbf{Alternativa E}
  \begin{itemize}
    \item \textit{Raciocínio provável}: Supor que a desaceleração da estrutura muda a velocidade do centro de massa do sistema.
    \item \textit{Tipo de erro}: Confusão entre velocidades e energia dissipada.
    \item \textit{Razão pela plausibilidade}: A velocidade do veículo diminui na colisão.
    \item \textit{Por que está errada}: A velocidade do centro de massa do sistema isolado permanece constante por conservação da quantidade de movimento.
  \end{itemize}

\end{itemize}

